START TRANSACTION;
CREATE TABLE "TaskBoards" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "CompanyId" bigint NOT NULL,
    "TaskTypeId" integer NOT NULL,
    "Name" text,
    "Deleted" boolean NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_TaskBoards" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TaskBoards_Companies_CompanyId" FOREIGN KEY ("CompanyId") REFERENCES "Companies" ("Id") ON DELETE CASCADE
);

CREATE TABLE "TaskBoardColumns" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "TaskBoardId" bigint NOT NULL,
    "Name" text,
    "SortOrder" integer NOT NULL,
    "IsDefault" boolean NOT NULL,
    "IsDoneColumn" boolean NOT NULL,
    "Deleted" boolean NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_TaskBoardColumns" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TaskBoardColumns_TaskBoards_TaskBoardId" FOREIGN KEY ("TaskBoardId") REFERENCES "TaskBoards" ("Id") ON DELETE CASCADE
);

CREATE TABLE "TaskRecurrences" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "CompanyId" bigint NOT NULL,
    "TaskBoardId" bigint NOT NULL,
    "Title" text,
    "Description" text,
    "Priority" integer NOT NULL,
    "DueDaysOffset" integer NOT NULL,
    "CronSchedule" text,
    "Enabled" boolean NOT NULL,
    "CreatedUserId" bigint NOT NULL,
    "LastTriggeredTime" timestamp with time zone,
    "Deleted" boolean NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_TaskRecurrences" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TaskRecurrences_Companies_CompanyId" FOREIGN KEY ("CompanyId") REFERENCES "Companies" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_TaskRecurrences_TaskBoards_TaskBoardId" FOREIGN KEY ("TaskBoardId") REFERENCES "TaskBoards" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_TaskRecurrences_Users_CreatedUserId" FOREIGN KEY ("CreatedUserId") REFERENCES "Users" ("Id") ON DELETE CASCADE
);

CREATE TABLE "TaskItems" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "CompanyId" bigint NOT NULL,
    "TaskBoardId" bigint NOT NULL,
    "TaskBoardColumnId" bigint NOT NULL,
    "Title" text,
    "Description" text,
    "Priority" integer NOT NULL,
    "Status" integer NOT NULL,
    "DueDate" timestamp with time zone,
    "CompletedDate" timestamp with time zone,
    "CreatedUserId" bigint NOT NULL,
    "RelatedCarId" bigint,
    "RelatedDriverId" bigint,
    "RecurrenceId" bigint,
    "SortOrder" integer NOT NULL,
    "Deleted" boolean NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_TaskItems" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TaskItems_Cars_RelatedCarId" FOREIGN KEY ("RelatedCarId") REFERENCES "Cars" ("Id"),
    CONSTRAINT "FK_TaskItems_Companies_CompanyId" FOREIGN KEY ("CompanyId") REFERENCES "Companies" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_TaskItems_TaskBoardColumns_TaskBoardColumnId" FOREIGN KEY ("TaskBoardColumnId") REFERENCES "TaskBoardColumns" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_TaskItems_TaskBoards_TaskBoardId" FOREIGN KEY ("TaskBoardId") REFERENCES "TaskBoards" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_TaskItems_TaskRecurrences_RecurrenceId" FOREIGN KEY ("RecurrenceId") REFERENCES "TaskRecurrences" ("Id"),
    CONSTRAINT "FK_TaskItems_Users_CreatedUserId" FOREIGN KEY ("CreatedUserId") REFERENCES "Users" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_TaskItems_Users_RelatedDriverId" FOREIGN KEY ("RelatedDriverId") REFERENCES "Users" ("Id")
);

CREATE TABLE "TaskRecurrenceAssignees" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "TaskRecurrenceId" bigint NOT NULL,
    "UserId" bigint NOT NULL,
    CONSTRAINT "PK_TaskRecurrenceAssignees" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TaskRecurrenceAssignees_TaskRecurrences_TaskRecurrenceId" FOREIGN KEY ("TaskRecurrenceId") REFERENCES "TaskRecurrences" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_TaskRecurrenceAssignees_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE CASCADE
);

CREATE TABLE "TaskAssignees" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "TaskItemId" bigint NOT NULL,
    "UserId" bigint NOT NULL,
    "AssignedTime" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_TaskAssignees" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TaskAssignees_TaskItems_TaskItemId" FOREIGN KEY ("TaskItemId") REFERENCES "TaskItems" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_TaskAssignees_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE CASCADE
);

CREATE TABLE "TaskAttachments" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "TaskItemId" bigint NOT NULL,
    "UploadedFileId" uuid NOT NULL,
    CONSTRAINT "PK_TaskAttachments" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TaskAttachments_TaskItems_TaskItemId" FOREIGN KEY ("TaskItemId") REFERENCES "TaskItems" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_TaskAttachments_UploadedFiles_UploadedFileId" FOREIGN KEY ("UploadedFileId") REFERENCES "UploadedFiles" ("Id") ON DELETE CASCADE
);

CREATE TABLE "TaskComments" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "TaskItemId" bigint NOT NULL,
    "UserId" bigint NOT NULL,
    "Text" text,
    "IsDeleted" boolean NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    "ModifiedTime" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_TaskComments" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TaskComments_TaskItems_TaskItemId" FOREIGN KEY ("TaskItemId") REFERENCES "TaskItems" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_TaskComments_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE CASCADE
);

CREATE TABLE "TaskNotifications" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "CompanyId" bigint NOT NULL,
    "UserId" bigint NOT NULL,
    "TaskItemId" bigint NOT NULL,
    "Message" text,
    "NotificationType" integer NOT NULL,
    "IsRead" boolean NOT NULL,
    "CreatedTime" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_TaskNotifications" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TaskNotifications_Companies_CompanyId" FOREIGN KEY ("CompanyId") REFERENCES "Companies" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_TaskNotifications_TaskItems_TaskItemId" FOREIGN KEY ("TaskItemId") REFERENCES "TaskItems" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_TaskNotifications_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE CASCADE
);

