ALTER TABLE "TaskBoards" ADD "TeamId" bigint;


                INSERT INTO "TaskTeams" ("CompanyId", "Name", "Description", "Color", "Deleted", "CreatedTime", "ModifiedTime")
                SELECT DISTINCT "CompanyId", 'General', 'Migrated from legacy boards', '#4A90D9', false, NOW(), NOW()
                FROM "TaskBoards"
                WHERE "Deleted" = false;

                UPDATE "TaskBoards" b
                SET "TeamId" = t."Id"
                FROM "TaskTeams" t
                WHERE t."CompanyId" = b."CompanyId" AND t."Name" = 'General';

                INSERT INTO "TaskTeamMembers" ("TaskTeamId", "UserId", "Role", "Deleted", "CreatedTime", "ModifiedTime")
                SELECT DISTINCT t."Id", u."Id", 0, false, NOW(), NOW()
                FROM "TaskTeams" t
                JOIN "Users" u ON u."CompanyId" = t."CompanyId" AND u."Role" IN (0, 6)
                WHERE t."Name" = 'General';


UPDATE "TaskBoards" SET "TeamId" = 0 WHERE "TeamId" IS NULL;
ALTER TABLE "TaskBoards" ALTER COLUMN "TeamId" SET NOT NULL;
ALTER TABLE "TaskBoards" ALTER COLUMN "TeamId" SET DEFAULT 0;

