START TRANSACTION;

                UPDATE "TaskItems" SET "Priority" = CASE
                    WHEN "Priority" = 3 THEN 5
                    WHEN "Priority" = 2 THEN 3
                    WHEN "Priority" = 1 THEN 2
                    WHEN "Priority" = 0 THEN 1
                    WHEN "Priority" = -1 THEN 0
                    ELSE 0
                END;
                UPDATE "TaskRecurrences" SET "Priority" = CASE
                    WHEN "Priority" = 3 THEN 5
                    WHEN "Priority" = 2 THEN 3
                    WHEN "Priority" = 1 THEN 2
                    WHEN "Priority" = 0 THEN 1
                    WHEN "Priority" = -1 THEN 0
                    ELSE 0
                END;


