                DELETE FROM "TaskTeamMembers" tm
                USING "Users" u
                WHERE tm."UserId" = u."Id" AND u."Role" IN (0, 6);



                INSERT INTO "TaskTeamMembers" ("TaskTeamId", "UserId", "Role", "Deleted", "CreatedTime", "ModifiedTime")
                SELECT t."Id", u."Id", 0, false, NOW(), NOW()
                FROM "TaskTeams" t
                JOIN "Users" u ON u."CompanyId" = t."CompanyId" AND u."Role" IN (1, 4)
                WHERE NOT EXISTS (
                    SELECT 1 FROM "TaskTeamMembers" existing
                    WHERE existing."TaskTeamId" = t."Id"
                      AND existing."UserId" = u."Id"
                      AND existing."Deleted" = false
                );


